<script setup>
import { onMounted, reactive, ref } from 'vue'; import { getProfile, updateProfile } from '../api'; import NoticeBar from '../components/NoticeBar.vue'; import PageHeader from '../components/PageHeader.vue'
const form=reactive({}),notice=ref('');onMounted(async()=>Object.assign(form,await getProfile()))
const save=async()=>{try{const p=await updateProfile(form);Object.assign(form,p);localStorage.setItem('radar_profile',JSON.stringify(p));notice.value='个人画像已保存'}catch(e){notice.value=e.message}setTimeout(()=>notice.value='',2200)}
</script>
<template><div><NoticeBar :message="notice"/><PageHeader eyebrow="CAREER PROFILE" title="我的求职画像" subtitle="画像越准确，职位匹配与面试建议就越有参考价值。"><button class="btn primary" @click="save">保存档案</button></PageHeader><div class="profile-layout"><section class="profile-intro"><div class="profile-avatar">{{(form.name||form.username||'同').slice(0,1)}}</div><h2>{{form.name||'同学'}}</h2><p>{{form.targetRole||'设置你的目标岗位'}}</p><div class="radar-visual"><i></i><i></i><i></i><span>能力画像<br><b>{{form.skills?'已激活':'待完善'}}</b></span></div><small>技能、经验、地点与薪资共同决定匹配结果</small></section><form class="profile-form" @submit.prevent="save"><div class="form-section"><h2>基本信息</h2><div class="form-grid"><label>姓名<input v-model="form.name" /></label><label>目标岗位<input v-model="form.targetRole" placeholder="Java 开发工程师" /></label><label>期望城市<input v-model="form.city" /></label><label>最高学历<input v-model="form.education" /></label><label>工作经验（年）<input v-model.number="form.experienceYears" type="number" min="0" /></label><span></span><label>最低期望薪资（元/月）<input v-model.number="form.salaryMin" type="number" /></label><label>最高期望薪资（元/月）<input v-model.number="form.salaryMax" type="number" /></label></div></div><div class="form-section"><h2>技能与介绍</h2><label>核心技能<input v-model="form.skills" placeholder="Java,Spring Boot,MySQL,Vue" /><small>请使用英文逗号分隔，匹配引擎会逐项计算</small></label><label>个人介绍<textarea v-model="form.introduction" rows="6" placeholder="介绍项目经历、技术优势和职业方向…"></textarea></label></div></form></div></div></template>
